import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import { FaHeart, FaRegHeart, FaComment, FaShare, FaThumbsUp, FaThumbsDown } from 'react-icons/fa';
import moment from 'moment';
import toast from 'react-hot-toast';

export default function VideoPlayer() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [video, setVideo] = useState(null);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState('');
    const [recommendations, setRecommendations] = useState([]);
    const [isLiked, setIsLiked] = useState(false);
    const [likesCount, setLikesCount] = useState(0);
    const [isSubscribed, setIsSubscribed] = useState(false);
    const videoRef = useRef();

    useEffect(() => {
        fetchVideo();
        fetchComments();
        fetchRecommendations();
        incrementView();
    }, [id]);

    const fetchVideo = async () => {
        try {
            const response = await axios.get(`/videos/${id}/`);
            setVideo(response.data);
            setIsLiked(response.data.is_liked || false);
            setLikesCount(response.data.like_count || 0);
        } catch (error) {
            console.error('Error fetching video:', error);
            toast.error('Видео не найдено');
            navigate('/');
        }
    };

    const fetchComments = async () => {
        try {
            const response = await axios.get(`/videos/comments/?video_id=${id}`);
            setComments(response.data.results || response.data);
        } catch (error) {
            console.error('Error fetching comments:', error);
        }
    };

    const fetchRecommendations = async () => {
        try {
            const response = await axios.get('/videos/recommended/');
            setRecommendations(response.data.filter(v => v.id !== parseInt(id)).slice(0, 10));
        } catch (error) {
            console.error('Error fetching recommendations:', error);
        }
    };

    const incrementView = async () => {
        try {
            await axios.post(`/videos/${id}/view/`);
        } catch (error) {
            console.error('Error incrementing view:', error);
        }
    };

    const handleLike = async () => {
        if (!user) {
            toast.error('Войдите чтобы поставить лайк');
            return;
        }
        try {
            const response = await axios.post(`/videos/${id}/like/`);
            setIsLiked(response.data.status === 'liked');
            setLikesCount(response.data.count);
            toast.success(response.data.status === 'liked' ? 'Лайк добавлен' : 'Лайк убран');
        } catch (error) {
            console.error('Error liking video:', error);
            toast.error('Ошибка');
        }
    };

    const handleComment = async (e) => {
        e.preventDefault();
        if (!user) {
            toast.error('Войдите чтобы оставить комментарий');
            return;
        }
        if (!newComment.trim()) {
            toast.error('Напишите комментарий');
            return;
        }

        try {
            await axios.post('/videos/comments/', {
                video: id,
                text: newComment
            });
            setNewComment('');
            fetchComments();
            toast.success('Комментарий добавлен');
        } catch (error) {
            toast.error('Ошибка добавления комментария');
        }
    };

    const handleSubscribe = async () => {
        if (!user) {
            toast.error('Войдите чтобы подписаться');
            return;
        }
        if (user.id === video.author.id) {
            toast.error('Нельзя подписаться на себя');
            return;
        }
        try {
            const response = await axios.post(`/users/${video.author.id}/subscribe/`);
            setIsSubscribed(response.data.status === 'subscribed');
            setVideo({
                ...video,
                author: {
                    ...video.author,
                    subscriber_count: response.data.count
                }
            });
            toast.success(response.data.status === 'subscribed' ? 'Подписан' : 'Отписан');
        } catch (error) {
            toast.error('Ошибка');
        }
    };

    const deleteComment = async (commentId) => {
        if (!user) return;
        try {
            await axios.delete(`/videos/comments/${commentId}/`);
            fetchComments();
            toast.success('Комментарий удален');
        } catch (error) {
            toast.error('Ошибка удаления');
        }
    };

    if (!video) return (
        <div className="flex justify-center items-center h-screen">
            <div className="text-white text-xl">Загрузка...</div>
        </div>
    );

    return (
        <div className="pt-16 bg-black min-h-screen">
            <div className="container mx-auto px-4 py-8">
                <div className="flex flex-col lg:flex-row gap-8">
                    {/* Левая колонка - видео и детали */}
                    <div className="lg:w-3/4">
                        {/* Видео плеер */}
                        <div className="bg-black rounded-xl overflow-hidden shadow-2xl">
                            <video
                                ref={videoRef}
                                controls
                                autoPlay
                                className="w-full"
                                style={{ maxHeight: '70vh' }}
                                src={video.video_file}
                            >
                                Ваш браузер не поддерживает видео
                            </video>
                        </div>

                        {/* Информация о видео */}
                        <div className="mt-6">
                            <h1 className="text-2xl font-bold text-white">{video.title}</h1>

                            {/* Канал и действия */}
                            <div className="flex flex-wrap items-center justify-between gap-4 mt-4 pb-4 border-b border-gray-800">
                                <div className="flex items-center space-x-4">
                                    <div className="flex items-center space-x-3">
                                        <div className="w-12 h-12 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center cursor-pointer">
                                            <span className="text-white font-bold text-lg">
                                                {video.author?.username?.[0]?.toUpperCase()}
                                            </span>
                                        </div>
                                        <div>
                                            <p className="font-semibold text-white hover:text-purple-400 cursor-pointer">
                                                {video.author?.username}
                                            </p>
                                            <p className="text-sm text-gray-400">{video.author?.subscriber_count} подписчиков</p>
                                        </div>
                                    </div>
                                    <button
                                        onClick={handleSubscribe}
                                        className={`px-6 py-2 rounded-full font-semibold transition ${
                                            isSubscribed 
                                                ? 'bg-gray-700 text-white hover:bg-gray-600' 
                                                : 'bg-red-600 text-white hover:bg-red-700'
                                        }`}
                                    >
                                        {isSubscribed ? 'Отписаться' : 'Подписаться'}
                                    </button>
                                </div>

                                <div className="flex items-center space-x-3">
                                    <button
                                        onClick={handleLike}
                                        className={`flex items-center space-x-2 px-6 py-2 rounded-full font-semibold transition ${
                                            isLiked 
                                                ? 'bg-blue-600 text-white' 
                                                : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                                        }`}
                                    >
                                        {isLiked ? <FaThumbsUp className="text-lg" /> : <FaHeart className="text-lg" />}
                                        <span>{likesCount}</span>
                                    </button>
                                    <button className="flex items-center space-x-2 px-6 py-2 bg-gray-800 rounded-full hover:bg-gray-700 transition text-gray-300">
                                        <FaShare />
                                        <span>Поделиться</span>
                                    </button>
                                </div>
                            </div>

                            {/* Описание видео */}
                            <div className="mt-4 p-4 bg-gray-900 rounded-xl">
                                <div className="flex items-center space-x-4 text-sm text-gray-400 mb-3">
                                    <span>{video.views.toLocaleString()} просмотров</span>
                                    <span>•</span>
                                    <span>{moment(video.created_at).format('DD MMMM YYYY')}</span>
                                </div>
                                <p className="text-gray-300 whitespace-pre-wrap">{video.description || 'Нет описания'}</p>
                            </div>

                            {/* Комментарии */}
                            <div className="mt-8">
                                <h3 className="text-xl font-bold text-white mb-4 flex items-center space-x-2">
                                    <FaComment className="text-purple-500" />
                                    <span>Комментарии ({comments.length})</span>
                                </h3>

                                {/* Форма добавления комментария */}
                                <form onSubmit={handleComment} className="mb-8">
                                    <div className="flex space-x-3">
                                        <div className="flex-shrink-0">
                                            <div className="w-10 h-10 bg-gray-700 rounded-full flex items-center justify-center">
                                                <span className="text-white">
                                                    {user ? user.username?.[0]?.toUpperCase() : '?'}
                                                </span>
                                            </div>
                                        </div>
                                        <div className="flex-1">
                                            <input
                                                type="text"
                                                value={newComment}
                                                onChange={(e) => setNewComment(e.target.value)}
                                                placeholder={user ? "Напишите комментарий..." : "Войдите чтобы оставить комментарий"}
                                                disabled={!user}
                                                className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-full text-white focus:outline-none focus:border-purple-500 disabled:opacity-50"
                                            />
                                        </div>
                                        {user && (
                                            <button
                                                type="submit"
                                                className="px-6 py-2 bg-purple-600 text-white rounded-full hover:bg-purple-700 transition font-semibold"
                                            >
                                                Отправить
                                            </button>
                                        )}
                                    </div>
                                </form>

                                {/* Список комментариев */}
                                <div className="space-y-4 max-h-96 overflow-y-auto">
                                    {comments.length === 0 ? (
                                        <div className="text-center text-gray-500 py-8">
                                            <p>Нет комментариев. Будьте первым!</p>
                                        </div>
                                    ) : (
                                        comments.map(comment => (
                                            <div key={comment.id} className="p-4 bg-gray-900 rounded-xl hover:bg-gray-800 transition">
                                                <div className="flex items-start justify-between">
                                                    <div className="flex-1">
                                                        <div className="flex items-center space-x-2 mb-2">
                                                            <div className="w-8 h-8 bg-gray-700 rounded-full flex items-center justify-center">
                                                                <span className="text-white text-sm">
                                                                    {comment.user.username?.[0]?.toUpperCase()}
                                                                </span>
                                                            </div>
                                                            <span className="font-semibold text-purple-400 hover:text-purple-300 cursor-pointer">
                                                                {comment.user.username}
                                                            </span>
                                                            <span className="text-gray-500 text-xs">
                                                                {moment(comment.created_at).fromNow()}
                                                            </span>
                                                        </div>
                                                        <p className="text-gray-300">{comment.text}</p>
                                                    </div>
                                                    {user && (user.id === comment.user.id || user.is_staff) && (
                                                        <button
                                                            onClick={() => deleteComment(comment.id)}
                                                            className="text-gray-500 hover:text-red-500 transition text-sm"
                                                        >
                                                            Удалить
                                                        </button>
                                                    )}
                                                </div>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Правая колонка - рекомендации */}
                    <div className="lg:w-1/4">
                        <h3 className="text-xl font-bold text-white mb-4 flex items-center space-x-2">
                            <span>🎬</span>
                            <span>Рекомендации</span>
                        </h3>
                        <div className="space-y-4">
                            {recommendations.length === 0 ? (
                                <div className="text-center text-gray-500 py-8">
                                    <p>Нет рекомендаций</p>
                                </div>
                            ) : (
                                recommendations.map(rec => (
                                    <div
                                        key={rec.id}
                                        onClick={() => navigate(`/video/${rec.id}`)}
                                        className="cursor-pointer group bg-gray-900 rounded-lg overflow-hidden hover:bg-gray-800 transition"
                                    >
                                        <div className="flex space-x-3 p-3">
                                            <div className="w-32 h-20 bg-gray-800 rounded-lg overflow-hidden flex-shrink-0">
                                                {rec.thumbnail ? (
                                                    <img 
                                                        src={rec.thumbnail} 
                                                        alt={rec.title} 
                                                        className="w-full h-full object-cover group-hover:scale-105 transition"
                                                    />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center text-3xl bg-gradient-to-br from-purple-900 to-pink-900">
                                                        🎬
                                                    </div>
                                                )}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <p className="text-sm font-semibold text-white line-clamp-2 group-hover:text-purple-400 transition">
                                                    {rec.title}
                                                </p>
                                                <p className="text-xs text-gray-400 mt-1">{rec.author?.username}</p>
                                                <p className="text-xs text-gray-500">{rec.views.toLocaleString()} просмотров</p>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
